const formatRelativeLocale = {
  lastWeek: (date) => {
    const day = date.getDay();

    switch (day) {
      case 0:
        return "'锌褉芯褕谢械 薪械写械褭械 褍' p";
      case 3:
        return "'锌褉芯褕谢械 褋褉械写械 褍' p";
      case 6:
        return "'锌褉芯褕谢械 褋褍斜芯褌械 褍' p";
      default:
        return "'锌褉芯褕谢懈' EEEE '褍' p";
    }
  },
  yesterday: "'褬褍褔械 褍' p",
  today: "'写邪薪邪褋 褍' p",
  tomorrow: "'褋褍褌褉邪 褍' p",
  nextWeek: (date) => {
    const day = date.getDay();

    switch (day) {
      case 0:
        return "'褋谢械写械褯械 薪械写械褭械 褍' p";
      case 3:
        return "'褋谢械写械褯褍 褋褉械写褍 褍' p";
      case 6:
        return "'褋谢械写械褯褍 褋褍斜芯褌褍 褍' p";
      default:
        return "'褋谢械写械褯懈' EEEE '褍' p";
    }
  },
  other: "P",
};

export const formatRelative = (token, date, _baseDate, _options) => {
  const format = formatRelativeLocale[token];

  if (typeof format === "function") {
    return format(date);
  }

  return format;
};
